→ [{"originalText":"벨N 카본 듀얼","matchedProduct":"카본 듀얼 SCF 93D-G","quantity":1,"confidence":"medium","alternatives":["카본 듀얼 SCF 103D-G","카본 듀얼 SCF 116D-G"]}]

