→ [{"originalText":"CFK 80 싱글","matchedProduct":"카본 싱글 CFK 80S-G","quantity":1,"confidence":"high","alternatives":[]}]

입력: "레듀샤 54-76 하나"
→ [{"originalText":"레듀샤 54-76 하나","matchedProduct":"실리콘 레듀샤 SR5476","quantity":1,"confidence":"high","alternatives":[]}]

